"""Starlette routing — Route, Router, and Mount classes."""
from __future__ import annotations

import asyncio
import re
from typing import Any, Callable, Dict, List, Optional, Pattern, Sequence, Set, Tuple, Type, Union

from starlette.requests import Request
from starlette.responses import PlainTextResponse, Response
from starlette.types import ASGIApp, Receive, Scope, Send
from starlette.websockets import WebSocket


class Match:
    NONE = 0
    PARTIAL = 1
    FULL = 2


class Route:
    """
    A single HTTP route that matches a URL pattern and dispatches to an endpoint.

    Usage::

        async def homepage(request):
            return PlainTextResponse("Hello, world!")

        routes = [
            Route("/", homepage),
        ]
    """

    def __init__(
        self,
        path: str,
        endpoint: Callable,
        *,
        methods: Optional[List[str]] = None,
        name: Optional[str] = None,
        include_in_schema: bool = True,
        middleware: Optional[Sequence[Any]] = None,
    ) -> None:
        self.path = path
        self.endpoint = endpoint
        self.methods = {m.upper() for m in methods} if methods else None
        self.name = name or getattr(endpoint, "__name__", None)
        self.include_in_schema = include_in_schema
        self.path_regex, self.path_format, self.param_convertors = compile_path(path)

    def matches(self, scope: Dict[str, Any]) -> Tuple[int, Dict[str, Any]]:
        if scope["type"] == "http":
            path = scope["path"]
            match = self.path_regex.match(path)
            if match:
                params = dict(scope.get("path_params", {}))
                params.update(match.groupdict())
                if self.methods and scope["method"] not in self.methods:
                    return Match.PARTIAL, {}
                return Match.FULL, params
        return Match.NONE, {}

    async def handle(self, scope: Scope, receive: Receive, send: Send) -> None:
        request = Request(scope, receive, send)
        if asyncio.iscoroutinefunction(self.endpoint):
            response = await self.endpoint(request)
        else:
            response = self.endpoint(request)
        await response(scope, receive, send)

    def url_path_for(self, name: str, **path_params: Any) -> str:
        if self.name != name:
            raise KeyError(name)
        path = self.path_format
        for key, value in path_params.items():
            path = path.replace(f"{{{key}}}", str(value))
        return path


class Router:
    """
    Base ASGI router that dispatches requests to matching routes.

    Usage::

        app = Router(routes=[
            Route("/", homepage),
            Route("/users", list_users),
        ])
    """

    def __init__(
        self,
        routes: Optional[List[Any]] = None,
        redirect_slashes: bool = True,
        default: Optional[ASGIApp] = None,
        on_startup: Optional[Sequence[Callable]] = None,
        on_shutdown: Optional[Sequence[Callable]] = None,
        lifespan: Optional[Any] = None,
    ) -> None:
        self.routes = list(routes or [])
        self.redirect_slashes = redirect_slashes
        self.default = default
        self.on_startup = list(on_startup or [])
        self.on_shutdown = list(on_shutdown or [])

    async def __call__(self, scope: Scope, receive: Receive, send: Send) -> None:
        scope_type = scope.get("type")
        if scope_type in ("http", "websocket"):
            await self.handle(scope, receive, send)
        elif scope_type == "lifespan":
            await self.lifespan(scope, receive, send)

    async def handle(self, scope: Scope, receive: Receive, send: Send) -> None:
        partial = None
        for route in self.routes:
            match, child_scope = route.matches(scope)
            if match == Match.FULL:
                scope.update(child_scope)
                await route.handle(scope, receive, send)
                return
            elif match == Match.PARTIAL and partial is None:
                partial = (route, child_scope)
        if partial is not None:
            route, child_scope = partial
            scope.update(child_scope)
            await route.handle(scope, receive, send)
        elif self.default is not None:
            await self.default(scope, receive, send)

    def add_route(self, path: str, endpoint: Callable, *, methods: Optional[List[str]] = None, name: Optional[str] = None) -> None:
        self.routes.append(Route(path=path, endpoint=endpoint, methods=methods, name=name))


def compile_path(path: str) -> Tuple[Pattern, str, Dict]:
    """Compile a path string into a regex pattern."""
    param_convertors = {}
    path_regex = "^"
    path_format = ""
    for part in re.split(r"({[^}]+})", path):
        if part.startswith("{") and part.endswith("}"):
            param = part[1:-1]
            param_convertors[param] = str
            path_regex += f"(?P<{param}>[^/]+)"
            path_format += f"{{{param}}}"
        else:
            path_regex += re.escape(part)
            path_format += part
    path_regex += "$"
    return re.compile(path_regex), path_format, param_convertors
